import csv

def count_rows(file_name):
 with open(file_name, 'r') as csvfile:
 reader = csv.reader(csvfile)
 return sum(1 for row in reader)

if __name__ == '__main__':
 filename = 'data.csv'
 print(count_rows(filename)) # 500

